Here are the MSTest comparison assertions you need and a complete test class:

**Key assertions for boundary checking:**

```csharp
Assert.IsGreaterThan(lowerBound, actual);   // actual > lowerBound
Assert.IsLessThan(upperBound, actual);      // actual < upperBound
Assert.IsInRange(actual, low, high);        // low <= actual <= high
```

**Complete test class:**

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsGreaterThanZero()
    {
        var result = _calculator.CalculatePercentage(1, 10);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NotPerfect_IsLessThanHundred()
    {
        var result = _calculator.CalculatePercentage(9, 10);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(95.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(85.0, "B")]
    [DataRow(80.0, "B")]
    [DataRow(75.0, "C")]
    [DataRow(70.0, "C")]
    [DataRow(65.0, "D")]
    [DataRow(60.0, "D")]
    [DataRow(55.0, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_IsInRange()
    {
        var result = _calculator.NormalizeScore(75, 150);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAtHundred()
    {
        var result = _calculator.NormalizeScore(200, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ZeroScore_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0, 100);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }
}
```

**Summary of comparison assertions used:**

| Assertion | Meaning | Use case |
|-----------|---------|----------|
| `Assert.IsGreaterThan(0.0, result)` | result > 0 | Partial scores are positive |
| `Assert.IsLessThan(100.0, result)` | result < 100 | Non-perfect scores below max |
| `Assert.IsInRange(result, 0.0, 100.0)` | 0 ≤ result ≤ 100 | Scores stay in valid range |

These give much better failure messages than `Assert.IsTrue(result > 0)` — on failure they report the actual value and the bound that was violated.
